#!/usr/bin/env node
"use strict";var node_fs=require("node:fs");var node_path=require("node:path");var node_child_process=require("node:child_process");const IS_WINDOWS=process.platform==="win32";const PATH_SEP=IS_WINDOWS?";":":";const PATHEXT=IS_WINDOWS?(process.env.PATHEXT??".COM;.EXE;.BAT;.CMD").split(";").map(s=>s.toLowerCase()):[""];function is_safe_subcommand_name(name){return/^[a-z0-9][\w.-]*$/i.test(name)&&!name.includes("..")}async function findPluginOnPath(subcommand,pathEnv){if(!pathEnv)return null;if(!is_safe_subcommand_name(subcommand))return null;const dirs=pathEnv.split(PATH_SEP).filter(d=>d.length>0);const baseName=`fsl-${subcommand}`;const NODE_EXTS=[".cjs",".mjs",".js"];const exts=IS_WINDOWS?[...PATHEXT,...NODE_EXTS]:["",...NODE_EXTS];for(const dir of dirs){for(const ext of exts){const candidate=node_path.join(dir,baseName+ext);try{const st=await node_fs.promises.stat(candidate);if(st.isFile())return candidate}catch{}}}return null}function isInProcessEligible(resolvedPath){const ext=node_path.extname(resolvedPath).toLowerCase();if(ext!==".js"&&ext!==".mjs"&&ext!==".cjs")return false;const norm=resolvedPath.replace(/\\/g,"/");return norm.includes("/node_modules/")}async function invokeInProcess(pluginPath,argv){const originalExit=process.exit;const originalArgv=process.argv;let interceptedExit=null;const ExitInterception=new Error("exit intercepted");process.exit=code=>{interceptedExit=typeof code==="number"?code:0;throw ExitInterception};process.argv=[originalArgv[0],pluginPath,...argv];let result;try{const mod=await import(pluginPath);const cli=mod&&(mod.default??mod);if(typeof cli==="function"){const r=await cli(argv);result=typeof r==="number"?r:0}else{process.stderr.write(`fsl: error: plugin ${pluginPath} is missing default cli() export\n`);result=2}}catch(error){if(error===ExitInterception){result=interceptedExit}else{process.stderr.write(`fsl: error: plugin threw: ${error.message??String(error)}\n`);result=2}}process.exit=originalExit;process.argv=originalArgv;return result}async function invokeBySpawn(pluginPath,argv){return new Promise(resolve=>{const ext=node_path.extname(pluginPath).toLowerCase();const isCmdScript=IS_WINDOWS&&(ext===".cmd"||ext===".bat");const isNodeScript=[".cjs",".mjs",".js"].includes(ext);const[spawnCmd,spawnArgs]=isCmdScript?["cmd.exe",["/c",pluginPath,...argv]]:isNodeScript?[process.execPath,[pluginPath,...argv]]:[pluginPath,argv];const child=node_child_process.spawn(spawnCmd,spawnArgs,{stdio:"inherit"});child.on("exit",code=>resolve(code));child.on("error",err=>{process.stderr.write(`fsl: error: failed to spawn plugin: ${err.message}\n`);resolve(2)})})}const RESERVED_FLAGS=new Set(["--help","-h","--version","-V"]);const RESERVED_NAMES=new Set(["help","version"]);const getDispatcherVersion=()=>"5.162.19";const printDispatcherHelp=()=>{process.stdout.write(`fsl — finite-state language toolchain dispatcher\n\nUsage:\n  fsl <subcommand> [options] [args...]\n  fsl [--help|--version]\n\nBuilt-in subcommands (resolved via PATH):\n  render                 Render FSL machines to SVG, DOT, PNG, JPEG, or HTML\n  export-system-prompt   Write the FSL system prompt for an LLM to stdout or a file\n\nDiscovery:\n  Any \`fsl-<name>\` executable on PATH is dispatched when you run\n  \`fsl <name>\`. Third-party plugins follow the same contract as\n  first-party ones.\n\n  See: https://github.com/StoneCypher/jssm\n`)};async function dispatch(argv){let verbose=false;if(argv[0]==="--verbose"){verbose=true;argv=argv.slice(1)}if(argv.length===0||RESERVED_FLAGS.has(argv[0])){if(argv[0]==="--version"||argv[0]==="-V"){process.stdout.write(`fsl ${getDispatcherVersion()}\n`);return 0}printDispatcherHelp();return 0}const subcommand=argv[0];if(RESERVED_NAMES.has(subcommand)){if(subcommand==="version"){process.stdout.write(`fsl ${getDispatcherVersion()}\n`);return 0}printDispatcherHelp();return 0}if(!is_safe_subcommand_name(subcommand)){process.stderr.write(`fsl: '${subcommand}' is not a valid subcommand name (only letters, digits, '.', '_', and '-' are allowed; no path separators or '..')\n`);return 1}const pluginPath=await findPluginOnPath(subcommand,process.env.PATH);if(!pluginPath){process.stderr.write(`fsl: '${subcommand}' is not a known subcommand and no \`fsl-${subcommand}\` was found on PATH\n`);return 1}if(verbose){process.stderr.write(`fsl: resolved '${subcommand}' to ${pluginPath}\n`)}const rest=argv.slice(1);if(isInProcessEligible(pluginPath)){return invokeInProcess(pluginPath,rest)}return invokeBySpawn(pluginPath,rest)}async function main(){const argv=process.argv.slice(2);const code=await dispatch(argv);process.exitCode=code}void main();